    92→function getPlainLines(content) {
    93→  if (!content) return [];
    94→  return content
    95→    .replace(/<[^>]+>/g, ' ')
    96→    .split('\n')
    97→    .map((line) => line.replace(/^#{1,6}\s*/, '').replace(/^[-*]\s*/, '').trim())
    98→    .filter(Boolean);
    99→}
   100→
   101→function sanitizeChecklistItem(value) {
   102→  return String(value || '')
   103→    .replace(/<[^>]+>/g, ' ')
   104→    .replace(/\s+/g, ' ')
   105→    .trim();
   106→}
   107→
   108→function getChecklistItems(content, bullets) {
   109→  const items = [];
   110→  const pushItem = (value) => {
   111→    const cleaned = sanitizeChecklistItem(value);
   112→    if (!cleaned) return;
   113→    if (/투자 전에 꼭 확인할 포인트/.test(cleaned)) return;
   114→    if (!items.includes(cleaned)) {
   115→      items.push(cleaned);
   116→    }
   117→  };
   118→
   119→  if (Array.isArray(bullets)) {
   120→    bullets.forEach(pushItem);
   121→  }
   122→
   123→  String(content || '')
   124→    .split('\n')
   125→    .forEach((line) => {
   126→      const match = line.match(/^\s*(?:[-*]|\d+[.)])\s+(.+)$/);
   127→      if (match?.[1]) {
   128→        pushItem(match[1]);
   129→      }
   130→    });
   131→
   132→  return items.slice(0, 5);
   133→}
